import React, { Suspense } from 'react'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import {
  List,
  ListItem,
  Button,
  DialogOverlayActions,
  DialogOverlay,
  DialogOverlayFooter,
  colors,
  Skeleton,
  H5,
} from '@fs/zion-ui'
import { trackEvent, trackLink } from '@fs/zion-analytics'
import { NoticeLoading } from '@fs/zion-icon'
import usePlaceDuplicateSuggestions from '../../hooks/usePlaceDuplicateSuggestions'
import HelpButton from '../HelpButton/HelpButton'

const HighlightMatchingText = React.lazy(() => import('../HighlightMatchingText/HighlightMatchingText'))

const listItemCss = css`
  display: flex;
  justify-content: space-between;
  margin: 0;
`
const skeletonWrapperCss = css`
  display: flex;
  justify-content: space-between;
  align-items: center;
`

function PrimaryText({ suggestion, highlightMatchingText, ignoreDiacritics, inputValue }) {
  if (highlightMatchingText) {
    return (
      <HighlightMatchingText textToHighlight={inputValue} ignoreDiacritics={ignoreDiacritics}>
        {suggestion.primaryText}
      </HighlightMatchingText>
    )
  }
  return suggestion.primaryText
}

function SecondaryText({ suggestion, highlightMatchingText, inputValue }) {
  return highlightMatchingText ? (
    <>
      <div>
        <HighlightMatchingText textToHighlight={inputValue}>{suggestion.secondaryText || ''}</HighlightMatchingText>
      </div>
      {suggestion.tertiaryText && (
        <div>
          <HighlightMatchingText textToHighlight={inputValue}>{suggestion.tertiaryText || ''}</HighlightMatchingText>
        </div>
      )}
    </>
  ) : (
    <>
      {suggestion.secondaryText || ''}
      {suggestion.tertiaryText || ''}
    </>
  )
}

export function fuzzyMatchNameToSuggestedName(searchTerm = '', text = '') {
  // Convert strings to lowercase for case-insensitive matching
  const searchTermLower = searchTerm.toLowerCase()
  const textLower = text.toLowerCase()

  // If text is empty, consider not a match
  if (text === '') {
    return false
  }

  // If the search term is empty, consider it a match
  if (searchTermLower === '') {
    return true
  }

  // Filter out whitespace and punctuation from both the search term and text
  const searchCharacters = [...searchTermLower].filter((char) => !/\s|[^\w]/.test(char))
  const textCharacters = [...textLower].filter((char) => !/\s|[^\w]/.test(char))

  const maxSkippedChars = Math.floor(searchCharacters.length / 5)
  let skippedChars = 0

  return searchCharacters.every((char) => {
    const foundIndex = textCharacters.indexOf(char)

    if (foundIndex !== -1) {
      // Remove the matched character from the text array to avoid duplicate matching
      textCharacters.splice(0, foundIndex + 1)
    } else {
      skippedChars++

      // If the number of skipped characters exceeds the dynamically calculated limit, return false
      if (skippedChars > maxSkippedChars) {
        return false
      }
    }

    return true
  })
}

export default function NewSearchSelectOrCreatePlaceContent({
  title,
  subtitle,
  overlay,
  provisionalPlaceFormValues,
  proposedSuggestions = [],
  onSearchAgain,
  onSelect,
  onNext,
}) {
  const [t] = useTranslation()
  const { suggestions, loading } = usePlaceDuplicateSuggestions({ initialValues: provisionalPlaceFormValues })
  const noMatchesStyle = { color: colors.danger40, fontWeight: 'bold' }
  const displaySuggestions = proposedSuggestions
    .filter((s) => fuzzyMatchNameToSuggestedName(provisionalPlaceFormValues?.placeName, s.primaryText))
    .concat(suggestions)
  const hasPosssibleMatches = displaySuggestions?.length > 0
  const createButtonEmphasis = hasPosssibleMatches ? 'medium' : 'high'

  return (
    <DialogOverlay title={title} subtitle={subtitle} {...overlay} closeOnClickAway={false}>
      <Suspense fallback={<NoticeLoading />}>
        {loading && (
          <>
            <Skeleton.H6 />
            <div className={skeletonWrapperCss}>
              <div style={{ width: '60%' }}>
                <Skeleton.ListItem hasSecondLine />
              </div>
              <Skeleton.Button />
            </div>
          </>
        )}
        {!loading && hasPosssibleMatches && (
          <>
            <H5>{t('provisional-place.possible-matches.warning', 'Possible Matches')}</H5>
            <List as="div" maxHeight="300px">
              {displaySuggestions.map((suggestion) => (
                <div key={suggestion.key} className={listItemCss}>
                  <ListItem
                    tabIndex={-1}
                    interactable
                    key={suggestion.key || suggestion.id}
                    primaryText={
                      <PrimaryText
                        highlightMatchingText
                        inputValue={provisionalPlaceFormValues?.placeName || ''}
                        suggestion={suggestion}
                        ignoreDiacritics
                      />
                    }
                    secondaryText={
                      <SecondaryText
                        highlightMatchingText
                        inputValue={provisionalPlaceFormValues?.placeName || ''}
                        suggestion={suggestion}
                      />
                    }
                    startElement={suggestion.startElement}
                    endElement={suggestion.endElement}
                  />
                  <div style={{ marginRight: 20 }}>
                    <Button
                      data-testid={`select-${suggestion.key}`}
                      emphasis="high"
                      onClick={() => {
                        if (onSelect) {
                          trackLink({
                            to: 'familysearch.org',
                            action: 'click_action',
                            name: 'ProvisionalPlace:Existing Place Select:Click',
                          })
                          trackEvent({ event_name: `chose existing place - ${suggestion?.primaryText}` })
                          onSelect(suggestion)
                        }
                      }}
                    >
                      {t('common-ui:select.action', 'Select')}
                    </Button>
                  </div>
                </div>
              ))}
            </List>
          </>
        )}
        {!loading && !hasPosssibleMatches && (
          <div style={noMatchesStyle}>{t('provisional-place.no-matches-found.warning', 'No Matches Found')}</div>
        )}
        <DialogOverlayFooter>
          <DialogOverlayActions>
            <HelpButton />
            <Button emphasis="medium" onClick={onSearchAgain}>
              {t('common-ui:back.action', 'Back')}
            </Button>
            <Button emphasis={createButtonEmphasis} type="submit" onClick={onNext}>
              {t('provisional-place.create-new-place.label', 'Create Place')}
            </Button>
          </DialogOverlayActions>
        </DialogOverlayFooter>
      </Suspense>
    </DialogOverlay>
  )
}
