import { useEffect, useState } from 'react'
import { getProvisionalPlaceDuplicateSuggestions } from '../lib/provisionalPlaceService'

export default function usePlaceDuplicateSuggestions({ initialValues = {} }) {
  const [loading, setLoading] = useState(true)
  const [values, setValues] = useState(initialValues)
  const [suggestions, setSuggestions] = useState([])
  const { placeName, parentPlace, placeType } = values
  const parentPlaceName = parentPlace?.selectedItem?.standard?.standardizedText
  const parentPlaceId = parentPlace?.selectedItem?.standard?.id
  const placeTypeName = placeType?.primaryText

  useEffect(() => {
    setLoading(true)
    getProvisionalPlaceDuplicateSuggestions({ placeName, parentPlaceName, parentPlaceId }).then((response) => {
      setSuggestions(response)
      setLoading(false)
    })
  }, [placeName, parentPlaceName, parentPlaceId, placeTypeName])

  return { values, suggestions, setValues, loading }
}
